import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend, CartesianGrid } from 'recharts';
import { useNavigate } from 'react-router-dom';

export default function AdminDashboard() {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    axios.get('/fees/dashboard').then(r => setStats(r.data)).catch(console.error).finally(() => setLoading(false));
  }, []);

  if (loading) return <div className="loading-screen" style={{ height: 300, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center' }}><div className="spinner" /><p style={{ color: 'var(--text-muted)', fontSize: 13, marginTop: 10 }}>Loading analytical data...</p></div>;
  if (!stats) return <div className="alert alert-error">⚠️ Failed to connect to server. Please check your connection.</div>;

  const fmt = n => `₹${Number(n || 0).toLocaleString('en-IN')}`;
  const total = (stats.summary?.collected || 0) + (stats.summary?.pending || 0) + (stats.summary?.overdue || 0);
  const collectionRate = total > 0 ? Math.round((stats.summary.collected / total) * 100) : 0;

  const pieData = [
    { name: 'Collected', value: stats.summary?.collected || 0, color: 'var(--success)' },
    { name: 'Pending', value: stats.summary?.pending || 0, color: 'var(--warning)' },
    { name: 'Overdue', value: stats.summary?.overdue || 0, color: 'var(--danger)' },
  ].filter(d => d.value > 0);

  const routeBarData = (stats.routeStats || []).map(r => ({
    name: `R-${r.route?.routeNumber || '?' }`,
    collected: parseFloat(r.dataValues?.totalCollected || 0),
    students: parseInt(r.dataValues?.count || 0),
  }));

  const statCards = [
    { label: 'Total Students', value: stats.totalStudents, icon: '🎓', cls: 'blue', sub: 'Active enrollments', action: () => navigate('/admin/students') },
    { label: 'Active Routes', value: stats.totalRoutes, icon: '🚌', cls: '', sub: 'Institutional bus lines', action: () => navigate('/admin/routes') },
    { label: 'Collected', value: fmt(stats.summary?.collected), icon: '✅', cls: 'green', sub: `${stats.paidCount || 0} payments`, action: () => navigate('/admin/fees') },
    { label: 'Pending', value: fmt(stats.summary?.pending), icon: '⏳', cls: 'yellow', sub: `${stats.pendingCount || 0} students`, action: () => navigate('/admin/upcoming') },
    { label: 'Overdue', value: fmt(stats.summary?.overdue), icon: '⚠️', cls: 'red', sub: 'Urgent collection needed', action: () => navigate('/admin/overdue') },
    { label: 'Success Rate', value: `${collectionRate}%`, icon: '📈', cls: 'blue', sub: 'Monthly collection target' },
  ];

  return (
    <>
      <div className="page-hero">
        <p className="page-hero-label">KEC Bus Portal — Administrator</p>
        <h2>Analytical Dashboard</h2>
        <p className="page-hero-meta">
          Monitoring {stats.totalStudents} students across {stats.totalRoutes} bus routes for {stats.currentMonth}
        </p>
      </div>

      <div className="stats-grid">
        {statCards.map(s => (
          <div
            key={s.label}
            className={`stat-card ${s.cls}`}
            onClick={s.action}
            style={{ cursor: s.action ? 'pointer' : 'default' }}
          >
            <div className="stat-label">{s.label}</div>
            <div className="stat-value">{s.value}</div>
            <div className="stat-sub">{s.sub}</div>
          </div>
        ))}
      </div>

      <div className="content-grid" style={{ marginBottom: 32 }}>
        {pieData.length > 0 && (
          <div className="card">
            <div className="card-header"><h3 className="card-title"><span>📊</span> Fee Distribution</h3></div>
            <div style={{ height: 260, padding: 20 }}>
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie data={pieData} cx="50%" cy="50%" innerRadius={60} outerRadius={85} paddingAngle={4} dataKey="value">
                    {pieData.map((e, i) => <Cell key={i} fill={e.color} />)}
                  </Pie>
                  <Tooltip formatter={v => fmt(v)} />
                  <Legend />
                </PieChart>
              </ResponsiveContainer>
            </div>
          </div>
        )}

        {routeBarData.length > 0 && (
          <div className="card">
            <div className="card-header"><h3 className="card-title"><span>🚌</span> Collection by Route</h3></div>
            <div style={{ height: 260, padding: 20 }}>
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={routeBarData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="var(--border)" />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 11 }} />
                  <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 11 }} />
                  <Tooltip cursor={{ fill: 'var(--surface2)' }} formatter={v => fmt(v)} />
                  <Bar dataKey="collected" fill="var(--primary)" radius={[6, 6, 0, 0]} barSize={24} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>
        )}
      </div>

      <div className="card">
        <div className="card-header">
          <h3 className="card-title"><span>📅</span> Route Operations Summary</h3>
          <button className="btn btn-secondary" style={{ padding: '6px 12px', fontSize: 12 }} onClick={() => navigate('/admin/fees')}>Details →</button>
        </div>
        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                <th>Route</th>
                <th>Student Count</th>
                <th>Revenue</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {routeBarData.map((r, i) => (
                <tr key={i}>
                  <td><strong>{r.name}</strong></td>
                  <td>{r.students} students</td>
                  <td><strong style={{ color: 'var(--success)' }}>{fmt(r.collected)}</strong></td>
                  <td><span className="badge badge-paid">Active</span></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </>
  );
}
